import { IErrorResponse } from '@domain/error';
import { toTitleCase } from '@utils/toTitleCase';
import { TFunction } from 'react-i18next';

type OptionParams = {
  error?: IErrorResponse;
  separator?: string;
  titleCase?: boolean;
};

export const formatErrorMessage = ({ error, separator, titleCase = true }: OptionParams) => {
  if (!error) {
    return '';
  }

  // When we get a network error it's this specific message by axios
  if (error.type === 'NETWORK_ERROR' && error.message) {
    return error.message;
  }

  const response =
    error?.errors
      ?.map((e) => e.details)
      ?.flat()
      ?.join(separator ?? ',') ?? '';

  if (titleCase) {
    return toTitleCase(response);
  }

  return response;
};

export const formatSubmissionErrorMessage = (
  error: IErrorResponse & { response?: { status: number } },
  t: TFunction
) => {
  const statusCode = error.response?.status;

  if (statusCode === 429) {
    return t('error.429');
  }

  if (statusCode && statusCode >= 500 && (!error?.errors || !error?.errors.length)) {
    return t('error.server', { statusCode });
  }

  return formatErrorMessage({ error });
};

