import { IErrorResponse } from '@domain/error';
import { yupResolver } from '@hookform/resolvers/yup';
import { usePrevious } from '@utils/usePrevious';
import { useEffect } from 'react';
import { DefaultValues, FieldValues, Mode, Path, useForm } from 'react-hook-form';
import { Schema } from 'yup';

// This converts our server errors to a format that react-hook-form understands
export function addServerError<T>(
  error: { attribute: string; details: string[] },
  setError: (name: Path<T>, error: { message: string; type: string }) => void
) {
  setError(error.attribute as Path<T>, {
    // Rule Name
    message: error.details.join('. '),
    type: 'server',
  });
}

export type UseEnhancedFormProps<TFormValues> = {
  context?: object;
  enableReinitialize?: boolean;
  initialValues?: DefaultValues<TFormValues>;
  mode?: Mode;
  schema?: Schema;
  serverError?: IErrorResponse | undefined | null;
};

export const useEnhancedForm = <T extends FieldValues>({
  context,
  enableReinitialize,
  initialValues,
  mode = 'onBlur',
  schema,
  serverError,
}: UseEnhancedFormProps<T>) => {
  const methods = useForm<T>({
    context,
    defaultValues: initialValues,
    mode,
    resolver: schema ? yupResolver(schema) : undefined,
  });

  const { getValues, reset } = methods;

  useEffect(() => {
    if (serverError?.errors) {
      serverError.errors.forEach((error) => {
        addServerError(error, methods.setError);
      });
    }
  }, [serverError, methods]);

  const previousInitialValues = usePrevious(initialValues);

  useEffect(() => {
    if (enableReinitialize) {
      const initialJSON = JSON.stringify(initialValues);
      const previousJSON = JSON.stringify(previousInitialValues);
      const currentJSON = JSON.stringify(getValues());

      const desynced = initialJSON !== previousJSON && initialJSON !== currentJSON;

      if (desynced) {
        reset(initialValues);
      }
    }
  }, [initialValues, enableReinitialize, previousInitialValues, getValues, reset]);

  return methods;
};

