import { useCallback, useEffect, useMemo } from 'react';
import { create } from 'zustand';

export type TurnstileOptions = {
  appearance?: 'always' | 'execute' | 'interaction-only';
  callback: (token: string) => void;
  mode?: 'non-interactive' | 'managed' | 'invisible';
  sitekey: string;
  theme?: 'light' | 'dark' | 'auto';
  'timeout-callback'?: () => void;
};

export type Turnstile = {
  ready: (callback: () => void) => void;
  remove: (id: string) => void;
  render: (containerSelector: string, options: TurnstileOptions) => string;
  reset: (id: string) => void;
};

type TurnstileWindow = Window & {
  onloadTurnstileCallback: () => void;
  turnstile: Turnstile;
};

declare const window: TurnstileWindow;

export type TurnstileRenderOptions = Omit<
  TurnstileOptions,
  'callback' | 'sitekey' | 'timeout-callback'
>;

const defaultRenderOptions: TurnstileRenderOptions = {
  appearance: 'interaction-only',
  mode: 'managed',
  theme: 'light',
};

const sitekey = process.env.VITE_CLOUDFLARE_SITE_KEY;

type TurnstileInitState = 'uninitialized' | 'loading' | 'initialized';
type TurnstileState = {
  initState: TurnstileInitState;
  response: string | undefined;
  setInitState: (initState: TurnstileInitState) => void;
  setResponse: (response: string | undefined) => void;
  setWidgetId: (widgetId: string) => void;
  widgetId: string;
};

const useTurnstileState = create<TurnstileState>((set) => ({
  initState: 'uninitialized',
  response: undefined,
  setInitState: (initialized) => set({ initState: initialized }),
  setResponse: (response) => set({ response }),
  setWidgetId: (widgetId) => set({ widgetId }),
  widgetId: '',
}));

const CONTAINER_ID = 'turnstile-widget';

type UseTurnstileProps = {
  initializeScript?: boolean;
};

// Relevant docs: https://developers.cloudflare.com/turnstile/get-started/client-side-rendering/

// This hook persists the turnstile widget state in zustand so that methods can be called on the widget from anywhere in the app (useful for resetting the widget when forms are submitted).
// Only a single widget can be rendered on a page at a time.
export const useTurnstile = ({ initializeScript = false }: UseTurnstileProps = {}) => {
  const [response, setResponse, setWidgetId, widgetId, initState, setInitState] = useTurnstileState(
    (state) => [
      state.response,
      state.setResponse,
      state.setWidgetId,
      state.widgetId,
      state.initState,
      state.setInitState,
    ]
  );

  const render = useCallback(
    (options: TurnstileRenderOptions) => {
      if (sitekey && !widgetId && initState === 'initialized') {
        const optionsWithDefaults: TurnstileOptions = {
          appearance: options.appearance ?? defaultRenderOptions.appearance,
          callback: setResponse,
          mode: options.mode ?? defaultRenderOptions.mode,
          sitekey,
          theme: options.theme ?? defaultRenderOptions.theme,
          'timeout-callback': () => setResponse(undefined),
        };
        const wid = window.turnstile.render(`#${CONTAINER_ID}`, {
          ...optionsWithDefaults,
          callback: setResponse,
          mode: options.mode ?? defaultRenderOptions.mode,
          sitekey,
          'timeout-callback': () => setResponse(undefined),
        });
        setWidgetId(wid);
      }
    },
    [initState, setResponse, setWidgetId, widgetId]
  );

  // Resetting the widget will re-request the challenge from the server
  // Documentation suggests this should occur automatically every 5 minutes but we've seen
  // instances where the challenge is not re-requested and the challenge remains in an invalid state after
  // the 5 minutes has elapsed. Consuming code may call this intermittenetly to ensure the challenge is up to date
  // It's also critical that the widget is reset when a form is submitted as the challenge is only valid for a single submission even
  // if the request returns an error response (e.g. validation errors)
  const reset = useCallback(
    () => (widgetId ? window.turnstile.reset(widgetId) : undefined),
    [widgetId]
  );

  // This is called when the component that houses the CF widget is unmounted so that subsequent renders will be assigned a new widget id
  const remove = useCallback(() => {
    if (widgetId) {
      window.turnstile.remove(widgetId);
      setWidgetId('');
    }
  }, [setWidgetId, widgetId]);

  // Load the turnstile script if it hasn't already been loaded
  useEffect(() => {
    if (initState === 'uninitialized' && initializeScript) {
      setInitState('loading');
      const script = document.createElement('script');
      script.src = 'https://challenges.cloudflare.com/turnstile/v0/api.js?render=explicit';
      script.async = true;
      script.defer = true;
      script.crossOrigin = 'anonymous';
      document.body.appendChild(script);
      script.onload = () => setInitState('initialized');
    }
  }, [initState, initializeScript, setInitState]);

  return useMemo(
    () => ({ containerId: CONTAINER_ID, initState, remove, render, reset, response }),
    [initState, remove, render, reset, response]
  );
};

