import { Box, Link as ChakraLink, Flex } from '@chakra-ui/react';
import {
  AccountDocument,
  AccountDocumentCategories,
  type AccountDocumentType,
  DocumentCategory,
  getRequiredDocumentCategories,
  getRequiredDocumentCategoriesByRequiredDocuments,
} from '@domain/accountDocument';
import { ApiClient } from '@service/anedot/client';
import { useGetAccountDocuments } from '@state/accountDocuments';
import { useGetAccount } from '@state/accounts';
import { Form } from '@ui/components/formControls/Form';
import { Loading } from '@ui/components/Loading';
import { Panel } from '@ui/components/Panel';
import { Heading, Paragraph } from '@ui/components/typography';
import { snakeToCamel } from '@utils/snakeToCamel';
import { useEffect, useMemo, useState } from 'react';
import { Trans, useTranslation } from 'react-i18next';
import { Link as RouterLink } from 'react-router-dom';
import * as yup from 'yup';
import { StepFooter } from '../StepFooter';
import { useSteps } from '../useSteps';
import { DocumentationUploader } from './DocumentationUploader';

const getFileByCategory = (
  accountDocuments: AccountDocument[] | undefined,
  categoryDocuments: AccountDocumentType[]
) => {
  return accountDocuments?.find(({ documentType }) => categoryDocuments.includes(documentType));
};

type DraftRequirementsErrorResponse = {
  errors: [{ details: string[] }];
};

const errorIsDraftRequirementsError = (e: unknown): e is DraftRequirementsErrorResponse => {
  return (e as DraftRequirementsErrorResponse).errors !== undefined;
};

export const getRequiredAccountDocuments = async ({ accountId }: { accountId: string }) => {
  return new ApiClient()
    .get<AccountDocumentCategories>(`/accounts/${accountId}/draft_requirements`)
    .then(() => [])
    .catch((e) => {
      // it's a little weird we're getting a 422 here to get the info we need, but this will
      //  make more sense when each document has it's own validation on the be and we want to
      //  check which documents are still required
      if (errorIsDraftRequirementsError(e)) {
        const details = e.errors[0].details;
        if (details) {
          const requiredDocuments = details.map((detail) => detail.split(' ')[0]);
          return requiredDocuments;
        }
      }
      return [];
    });
};

export function Documentation() {
  const { t } = useTranslation('organizationApplication', { keyPrefix: 'documentation' });
  const { navigateNextStep } = useSteps();

  const { currentAccount, isLoading } = useGetAccount();
  const { accountDocuments, accountDocumentsIsLoading } = useGetAccountDocuments();
  const [requiredDocumentCategories, setRequiredDocumentCategories] = useState<
    AccountDocumentCategories | Record<string, unknown>
  >({});
  const documentCategoryEntries = useMemo(
    () => Object.entries(requiredDocumentCategories) as [DocumentCategory, AccountDocumentType[]][],
    [requiredDocumentCategories]
  );

  // biome-ignore lint/correctness/useExhaustiveDependencies: this is to initialize the required documents when the page loads
  useEffect(() => {
    if (!currentAccount?.id) {
      return;
    }

    // the source of truth is from the server, but we do have a local fallback that should match if the server is not working
    getRequiredAccountDocuments({ accountId: currentAccount.id })
      .then((requiredDocuments: string[]) => {
        if (requiredDocuments.length === 0) {
          setRequiredDocumentCategories(
            getRequiredDocumentCategories({
              accountCategory: currentAccount.category,
              subCategory: currentAccount.subCategory,
              state: currentAccount.state,
            })
          );
          return;
        }
        setRequiredDocumentCategories(
          getRequiredDocumentCategoriesByRequiredDocuments(requiredDocuments)
        );
      })
      .catch(() => {
        setRequiredDocumentCategories(
          getRequiredDocumentCategories({
            accountCategory: currentAccount.category,
            subCategory: currentAccount.subCategory,
            state: currentAccount.state,
          })
        );
      });
  }, [currentAccount?.id]);

  const initialValues = useMemo(() => {
    const values: Record<string, boolean> = {};
    documentCategoryEntries.forEach(([documentCategory, categoryDocuments]) => {
      values[documentCategory] = !!getFileByCategory(accountDocuments, categoryDocuments);
    });
    return values;
  }, [accountDocuments, documentCategoryEntries]);

  const validationSchema = useMemo(() => {
    const shape: Record<string, yup.Schema<boolean | undefined>> = {};
    documentCategoryEntries.forEach(([documentCategory]) => {
      shape[documentCategory] = yup.boolean().oneOf([true], t('uploader.required') as string);
    });
    return yup.object().shape(shape);
  }, [documentCategoryEntries, t]);

  if (isLoading || accountDocumentsIsLoading) {
    return <Loading />;
  }

  if (!currentAccount?.category) {
    return (
      <Box>
        <Trans
          components={{ hlink: <ChakraLink as={RouterLink} to=".." /> }}
          i18nKey="categoryCheck"
          t={t}
        />
      </Box>
    );
  }

  return (
    <>
      <hgroup>
        <Heading as="h1">{t('heading')}</Heading>
        <Paragraph as="h2">{currentAccount?.displayName}</Paragraph>
      </hgroup>
      <Form
        enableReinitialize
        initialValues={initialValues}
        onSubmit={() => navigateNextStep()}
        schema={validationSchema}
      >
        <Flex direction="column" gap={6}>
          <Panel p={6} variant="primary">
            <Flex direction="column" gap={6}>
              <Box>
                <Paragraph as="h3">{t('subheading')}</Paragraph>
                <Paragraph>{t('intro')}</Paragraph>
              </Box>
              {documentCategoryEntries.map(([documentCategory, categoryDocuments]) => {
                const i18nKey = snakeToCamel(documentCategory);

                return (
                  <DocumentationUploader
                    currentFile={getFileByCategory(accountDocuments, categoryDocuments)}
                    description={t(`categories.${i18nKey}.description` as Parameters<typeof t>[0])}
                    documentCategory={documentCategory}
                    categoryDocuments={categoryDocuments}
                    isRequired
                    key={documentCategory}
                    label={t(`categories.${i18nKey}.heading` as Parameters<typeof t>[0])}
                  />
                );
              })}
              <Paragraph>{t('footer')}</Paragraph>
            </Flex>
          </Panel>
          <StepFooter />
        </Flex>
      </Form>
    </>
  );
}

