import { conditionalJsonLinter } from './conditionalJsonLinter';

describe('conditionalJsonLinter', () => {
  it('lints empty string without errors', () => {
    const text = Text.of(['']);
    const mockView = { state: { doc: text } } as EditorView;

    const linter = conditionalJsonLinter();

    expect(linter(mockView)).toStrictEqual([]);
  });

  it('lints with error', () => {
    // trailing comma error in JSON
    const text = Text.of(['{"hello": "error",}']);

    const mockView = { state: { doc: text } } as EditorView;

    const linter = conditionalJsonLinter();

    expect(linter(mockView)).toMatchInlineSnapshot(`
      [
